var result        = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var bpoflg       = stp.getDBFieldValue(result,"TSU_BK_BPO_FLG");
var bisitype       = stp.getDBFieldValue(result,"FA_BUSI_TYPE");
stp.writeLog("TSU_BK_BPO_FLG = "+bpoflg);
stp.writeLog("FA_BUSI_TYPE = "+bisitype);
stp.updateFieldValue("/root/domData","TSU_BK_BPO_FLG",bpoflg);
stp.updateFieldValue("/root/domData","FA_BUSI_TYPE",bisitype);



